import{_ as i,o as e,c as a,ai as l}from"./chunks/framework.ampVZV4B.js";const c=JSON.parse('{"title":"SQL 优化与执行计划面试指南","description":"","frontmatter":{},"headers":[],"relativePath":"database/sql-optimization.md","filePath":"database/sql-optimization.md"}'),n={name:"database/sql-optimization.md"};function t(o,s,r,d,h,p){return e(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="sql-优化与执行计划面试指南" tabindex="-1">SQL 优化与执行计划面试指南 <a class="header-anchor" href="#sql-优化与执行计划面试指南" aria-label="Permalink to “SQL 优化与执行计划面试指南”">​</a></h1><hr><h3 id="❓-面试官-如果线上发现一条慢查询-你的排查和优化思路是什么" tabindex="-1">❓ 面试官：如果线上发现一条慢查询，你的排查和优化思路是什么？ <a class="header-anchor" href="#❓-面试官-如果线上发现一条慢查询-你的排查和优化思路是什么" aria-label="Permalink to “❓ 面试官：如果线上发现一条慢查询，你的排查和优化思路是什么？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我会分四步走：1. 开启慢查询日志找到慢 SQL；2. 用 <code>EXPLAIN</code> 分析执行计划，看是否走索引；3. 检查 SQL 语句本身是否有优化空间（如避免 <code>SELECT *</code>、避免函数等）；4. 如果 SQL 没问题，考虑是否是表数据量过大，需要归档、分库分表或引入缓存。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>定位慢 SQL</strong>： <ul><li>临时排查：通过 <code>show processlist</code> 查看当前正在执行的慢语句。</li><li>系统排查：开启 <code>slow_query_log</code>，设置 <code>long_query_time</code>（通常设置为 1-2 秒），结合 <code>mysqldumpslow</code> 工具分析日志。</li></ul></li><li><strong>EXPLAIN 分析（核心）</strong>： <ul><li>查看 <code>type</code> 字段：确保访问类型至少达到 <code>range</code>（范围扫描），最好是 <code>ref</code>（非唯一索引）或 <code>eq_ref</code>（主键/唯一索引），绝不能是 <code>ALL</code>（全表扫描）。</li><li>查看 <code>key</code> 字段：确认是否使用了预期的索引。</li><li>查看 <code>rows</code> 字段：预估扫描的行数，越小越好。</li><li>查看 <code>Extra</code> 字段：警惕 <code>Using filesort</code>（文件排序，需优化）和 <code>Using temporary</code>（临时表，严重影响性能），尽量达到 <code>Using index</code>（覆盖索引）。</li></ul></li><li><strong>SQL 级优化</strong>： <ul><li>只查询需要的列，杜绝 <code>SELECT *</code>（减少网络带宽、IO 以及方便触发覆盖索引）。</li><li>避免在 <code>WHERE</code> 条件中对字段进行函数操作、数学运算或隐式类型转换，否则索引失效。</li><li>避免前导模糊查询 <code>LIKE &#39;%xxx&#39;</code>。</li><li><code>IN</code> 的元素不要太多，如果是连续的数字可以用 <code>BETWEEN</code> 代替。</li></ul></li><li><strong>表结构与架构优化</strong>： <ul><li>数据量极大（单表超千万）：考虑分库分表。</li><li>聚合查询慢：考虑将结果提前计算并存入 Redis，或引入 ES、ClickHouse 解决复杂查询。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 有时候我们会发现：SQL 明明有索引，测试环境跑得飞快，生产环境却偶尔极慢。这通常不是 SQL 的问题，而是<strong>偶发的系统资源争抢或锁等待</strong>。比如：</p><ul><li>后台正在执行大批量的 <code>UPDATE</code>，引发了大量的锁等待或死锁。</li><li>缓冲池（Buffer Pool）命中率下降，或者脏页刷盘（Flush）导致 IO 飙高。 这时候光靠 <code>EXPLAIN</code> 是没用的，还需要结合服务器 IO 监控和 <code>show engine innodb status</code> 综合排查。</li></ul><hr><h3 id="❓-面试官-深分页问题-limit-1000000-10-为什么慢-怎么优化" tabindex="-1">❓ 面试官：深分页问题（LIMIT 1000000, 10）为什么慢？怎么优化？ <a class="header-anchor" href="#❓-面试官-深分页问题-limit-1000000-10-为什么慢-怎么优化" aria-label="Permalink to “❓ 面试官：深分页问题（LIMIT 1000000, 10）为什么慢？怎么优化？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 深分页慢的原因是 MySQL 会先把前 1000010 条记录都查出来（并回表），然后丢弃前 1000000 条，只返回最后 10 条。这期间产生了海量的<strong>无用回表操作</strong>。优化方法主要有<strong>延迟关联（子查询法）</strong>和<strong>游标法（基于上一次的最大 ID）</strong>。</p><p><strong>📝 详细原理解析：</strong> 深分页的典型 SQL：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> create_time </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>优化方案 1：延迟关联（覆盖索引 + JOIN / 子查询）</strong> 思路：先利用覆盖索引把满足条件的 ID 查出来，由于不查完整数据，这一步极快；然后再用这些 ID 去跟原表 JOIN，获取完整数据。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 优化后：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> o.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders o</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> create_time </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) temp </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> o</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> temp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>优化方案 2：游标法（基于主键/时间戳游标）</strong> 思路：如果主键是连续递增的，且不需要跳页访问（只能上一页、下一页），可以直接记住上一页的最大 ID，下一次查询直接从该 ID 往后取。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 优化后（假设上一页最大 ID 是 1000000）：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>🌟 面试加分项（实战经验）：</strong> 在真实的 C 端业务中（比如淘宝订单列表、朋友圈），通常<strong>不允许用户直接跳到第 10000 页</strong>。所以我们在产品设计上就会规避深分页，比如只能&quot;滑动加载更多&quot;（使用游标法），或者限制最多只能看前 100 页。如果非要支持海量数据的跳页，我们通常会将数据同步到 Elasticsearch，由 ES 来负责复杂分页。</p><hr><h3 id="❓-面试官-如何优化-join-操作-什么是小表驱动大表" tabindex="-1">❓ 面试官：如何优化 JOIN 操作？什么是小表驱动大表？ <a class="header-anchor" href="#❓-面试官-如何优化-join-操作-什么是小表驱动大表" aria-label="Permalink to “❓ 面试官：如何优化 JOIN 操作？什么是小表驱动大表？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 优化 JOIN 的核心原则是<strong>小表驱动大表</strong>，并且<strong>被驱动表的关联字段一定要有索引</strong>。这是为了最小化嵌套循环的次数。</p><p><strong>📝 详细原理解析：</strong> MySQL 执行 JOIN 主要使用<strong>嵌套循环算法（Nested-Loop Join，NLJ）</strong>：</p><ol><li>先从驱动表（外层表）中取出一行数据。</li><li>拿着这一行数据的关联字段，去被驱动表（内层表）中查找匹配的行。</li><li>循环往复。</li></ol><p>假设表 A 有 100 条数据，表 B 有 10000 条数据。</p><ul><li>如果 A 驱动 B：外层循环 100 次，每次去 B 中找。如果 B 的关联字段有索引，B 的查找是 O(logN)。总代价相对较小。</li><li>如果 B 驱动 A：外层循环 10000 次，开销剧增。</li></ul><p><strong>如何确定驱动表</strong>：</p><ul><li><code>LEFT JOIN</code>：左表是驱动表，右表是被驱动表。</li><li><code>RIGHT JOIN</code>：右表是驱动表，左表是被驱动表。</li><li><code>INNER JOIN</code>：MySQL 优化器会自动选择<strong>数据量较小（或经过 WHERE 过滤后结果集较小）</strong>的表作为驱动表。</li></ul><p><strong>🌟 面试加分项（实战经验）：</strong> 在微服务架构下，由于数据库被拆分（分库分表），我们现在极少在数据库层面直接使用 <code>JOIN</code>，尤其是 3 张表以上的 <code>JOIN</code> 是被规约严令禁止的。通常的做法是在 Java 代码层的内存里做 JOIN：先查 A 表的集合，提取出关联 ID 的 List，再用 <code>WHERE id IN (...)</code> 去查 B 表，最后在内存里通过 <code>Map</code> 或 <code>Stream</code> 将数据拼装起来。这虽然增加了一次网络请求，但大幅减轻了数据库 CPU 的压力，且极利于后续的横向扩展。</p><hr><h3 id="❓-面试官-能看懂-explain-的结果吗-重点看哪几个字段" tabindex="-1">❓ 面试官：能看懂 EXPLAIN 的结果吗？重点看哪几个字段？ <a class="header-anchor" href="#❓-面试官-能看懂-explain-的结果吗-重点看哪几个字段" aria-label="Permalink to “❓ 面试官：能看懂 EXPLAIN 的结果吗？重点看哪几个字段？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><code>EXPLAIN</code> 是 SQL 调优最重要的工具。我主要看四个核心字段：<code>type</code>（有没有走全表扫描）、<code>key</code>（实际用了哪个索引）、<code>rows</code>（预估扫描行数）和 <code>Extra</code>（是否触发了文件排序或覆盖索引）。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>type（访问类型，性能从好到坏）</strong>： <ul><li><code>system / const</code>：系统表或只有一条数据（极好）。</li><li><code>eq_ref</code>：使用了主键或唯一索引扫描（好）。</li><li><code>ref</code>：使用了非唯一索引扫描。</li><li><code>range</code>：使用了索引进行范围查询（如 &gt;、&lt;、between、in）。</li><li><code>index</code>：全索引扫描（遍历了整棵索引树，比全表稍好，但仍需优化）。</li><li><strong><code>ALL</code>：全表扫描（最差，必须优化）。</strong></li></ul></li><li><strong>key</strong>： <ul><li>实际使用的索引名称。如果为 NULL，说明没走索引。</li></ul></li><li><strong>rows</strong>： <ul><li>优化器预估需要读取的行数。越小越好。</li></ul></li><li><strong>Extra（额外信息）</strong>： <ul><li><code>Using index</code>：完美！触发了覆盖索引，不需要回表。</li><li><code>Using index condition</code>：触发了索引下推（ICP）。</li><li><code>Using where</code>：在 Server 层进行了条件过滤。</li><li><strong><code>Using filesort</code></strong>：差！无法利用索引完成排序，在内存或磁盘中进行了额外的排序操作。必须通过建联合索引来优化。</li><li><strong><code>Using temporary</code></strong>：差！使用了临时表保存中间结果（常出现在 GROUP BY 时），开销极大。</li></ul></li></ol>`,37)])])}const g=i(n,[["render",t]]);export{c as __pageData,g as default};
